+    if schema_obj.get("type").and_then(serde_json::Value::as_str) != Some("object") {
+        return;
+    }
+
+    let properties = schema_obj
+        .entry("properties")
+        .or_insert_with(|| serde_json::json!({}));
+    let Some(properties_obj) = properties.as_object_mut() else {
+        return;
+    };
+
+    properties_obj
