+        let mut outbound = [0_u8; 4];
+        stream.read_exact(&mut outbound).await?;
+        assert_eq!(&outbound, b"pong");
+        Ok::<(), io::Error>(())
+    };
+
+    let (server_res, client_res) = tokio::join!(server, client);
+    server_res?;
+    client_res?;
